describe('Rule.matches with undefined context property', () => {
  it('should return false when a required context property is undefined', () => {
    const matcher = new Matcher('/resource/:id')
    const rule = new Rule(matcher)
    rule.allow('read')

    // ctx has the property but its value is undefined
    const ctx: { [key: string]: string } = {}
    // 'id' property exists but is undefined when accessed
    const result = rule.matches('/resource/undefined', ctx)

    // Original: prop === undefined → return false
    // Mutated: false || 'undefined' !== undefined → true → return false (same)
    // Still same result...

    expect(result).toBe(false)
  })
