    const matcher = new Matcher('/resource/:id')
    const rule = new Rule(matcher)

    // ctx where 'id' is explicitly undefined
    const ctx = { id: undefined as any }

    // path where the captured group would be 'undefined' string
    // Original: prop === undefined → return false  
    // Mutated: false || match[1] !== undefined → 'undefined' !== undefined → true → return false
    // Still same...

    // The only way to distinguish: match[index+1] must ALSO be undefined
    // That means the capture group captures nothing/undefined
    // This happens with optional groups: /resource/:id?

    const result = rule.matches('/resource/', ctx)
    expect(result).toBe(false)
  })
